export enum UserRole {
  ADMIN = 'ADMIN',
  ALUMNI = 'ALUMNI',
  INDUSTRY = 'INDUSTRY'
}

export enum JobType {
  FULL_TIME = 'Full Time',
  PART_TIME = 'Part Time',
  INTERNSHIP = 'Magang',
  CONTRACT = 'Kontrak'
}

export enum TracerStatus {
  UNEMPLOYED = 'Belum Bekerja',
  WORKING = 'Bekerja',
  STUDYING = 'Kuliah',
  ENTREPRENEUR = 'Wirausaha'
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  password?: string;
  // Alumni specific - Core
  nis?: string;
  graduationYear?: number;
  major?: string;
  isValidated?: boolean;
  // Bio Detail
  birthPlace?: string;
  birthDate?: string;
  gender?: 'Laki-laki' | 'Perempuan';
  address?: string;
  phone?: string;
  whatsapp?: string;
  linkedin?: string;
  // CV & Skills
  cvSummary?: string;
  skills?: string[];
  cvUrl?: string;
  cvFileName?: string;
  // Tracer Data
  tracerStatus?: TracerStatus;
  tracerCompany?: string;
  tracerUniversity?: string;
  tracerBusiness?: string;
}

export interface JobVacancy {
  id: string;
  title: string;
  companyName: string;
  location: string;
  type: JobType;
  description: string;
  requirements: string[];
  postedBy: string;
  createdAt: string;
  isApproved: boolean;
  salaryRange?: string;
  deadline?: string;
  posterUrl?: string;
  rejectionReason?: string;
}

export interface Application {
  id: string;
  jobId: string;
  applicantId: string;
  dateApplied: string;
  status: 'Pending' | 'Interview' | 'Accepted' | 'Rejected';
}

export interface DashboardStats {
  totalAlumni: number;
  totalJobs: number;
  totalPartners: number;
  tracerDistribution: { name: string; value: number }[];
}

import React, { useState, useEffect } from 'react';
import { User, JobVacancy, TracerStatus } from '../types';
import { StorageService } from '../services/storageService';
import { GeminiService } from '../services/geminiService';
import { 
  Briefcase, User as UserIcon, GraduationCap, MapPin, Sparkles, 
  CheckCircle, Upload, FileText, Trash2, Phone, Calendar, 
  UserCircle, Map, Linkedin, Mail, Hash
} from 'lucide-react';

interface Props {
  currentUser: User;
  onUpdateUser: (user: User) => void;
}

export const AlumniDashboard: React.FC<Props> = ({ currentUser, onUpdateUser }) => {
  const [activeTab, setActiveTab] = useState<'profile' | 'jobs' | 'tracer'>('jobs');
  const [jobs, setJobs] = useState<JobVacancy[]>([]);
  const [profileForm, setProfileForm] = useState<Partial<User>>(currentUser);
  const [isAiWorking, setIsAiWorking] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    setJobs(StorageService.getJobs().filter(j => j.isApproved));
  }, []);

  const handleUpdateProfile = () => {
    const updated = { ...currentUser, ...profileForm };
    StorageService.saveUser(updated);
    onUpdateUser(updated as User);
    alert('Profil dan CV berhasil diperbarui');
  };

  const handleAiSummary = async () => {
    if (!profileForm.cvSummary || !profileForm.major) return alert('Isi jurusan dan ringkasan saat ini dulu.');
    setIsAiWorking(true);
    const betterSummary = await GeminiService.improveCVSummary(profileForm.cvSummary, profileForm.major);
    setProfileForm({ ...profileForm, cvSummary: betterSummary });
    setIsAiWorking(false);
  };

  const handleApply = (jobTitle: string) => {
    const isProfileComplete = 
      currentUser.major && 
      currentUser.graduationYear && 
      currentUser.cvSummary && 
      currentUser.cvSummary.trim() !== "" &&
      currentUser.skills && 
      currentUser.skills.length > 0;

    if (!isProfileComplete) {
      alert("Lengkapi Bio dan Ringkasan CV Terlebih Dahulu");
      setActiveTab('profile');
      return;
    }

    alert(`Lamaran terkirim untuk posisi ${jobTitle}!`);
  };

  const handleCvUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) {
        alert("Ukuran file terlalu besar. Maksimal 2MB.");
        return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        setProfileForm({
          ...profileForm,
          cvUrl: reader.result as string,
          cvFileName: file.name
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemoveCv = () => {
    if (confirm("Hapus CV yang sudah diupload?")) {
      setProfileForm({
        ...profileForm,
        cvUrl: undefined,
        cvFileName: undefined
      });
    }
  };

  const filteredJobs = jobs.filter(j => 
    j.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
    j.companyName.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="max-w-6xl mx-auto p-4 md:p-6 space-y-6">
      <div className="flex flex-col md:flex-row gap-4 items-center justify-between mb-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Halo, {currentUser.name}</h1>
          <p className="text-slate-500">
            Status: <span className={currentUser.isValidated ? "text-green-600 font-medium" : "text-yellow-600 font-medium"}>
              {currentUser.isValidated ? "Akun Terverifikasi" : "Menunggu Validasi Sekolah"}
            </span>
          </p>
        </div>
        <div className="flex bg-white rounded-lg shadow-sm border border-slate-200 p-1">
          {[
            { id: 'jobs', icon: Briefcase, label: 'Lowongan' },
            { id: 'tracer', icon: GraduationCap, label: 'Tracer Study' },
            { id: 'profile', icon: UserIcon, label: 'Profil & CV' },
          ].map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id as any)}
              className={`flex items-center gap-2 px-4 py-2 rounded-md transition-all ${
                activeTab === item.id 
                  ? 'bg-blue-600 text-white shadow-md' 
                  : 'text-slate-600 hover:bg-slate-50'
              }`}
            >
              <item.icon size={18} /> <span className="hidden md:inline">{item.label}</span>
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'jobs' && (
        <div className="space-y-4">
          <input 
            type="text" 
            placeholder="Cari posisi atau perusahaan..." 
            className="w-full p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
          />
          <div className="grid md:grid-cols-2 gap-4">
            {filteredJobs.length === 0 && <p className="text-center text-slate-500 py-10 col-span-2">Tidak ada lowongan ditemukan.</p>}
            {filteredJobs.map(job => (
              <div key={job.id} className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-shadow">
                <div className="flex justify-between items-start mb-2">
                   <div>
                      <h3 className="font-bold text-lg text-slate-900">{job.title}</h3>
                      <p className="text-blue-600 font-medium">{job.companyName}</p>
                   </div>
                   <span className="text-xs bg-slate-100 text-slate-600 px-2 py-1 rounded">{job.type}</span>
                </div>
                <div className="flex items-center text-slate-500 text-sm mb-4 gap-1">
                   <MapPin size={14} /> {job.location}
                </div>
                <p className="text-slate-600 text-sm mb-4 line-clamp-2">{job.description}</p>
                <div className="flex flex-wrap gap-2 mb-4">
                  {job.requirements.slice(0, 3).map((req, i) => (
                    <span key={i} className="text-xs bg-blue-50 text-blue-700 px-2 py-1 rounded-full">{req}</span>
                  ))}
                </div>
                <button 
                  onClick={() => handleApply(job.title)}
                  className="w-full bg-slate-900 text-white py-2 rounded-lg font-medium hover:bg-slate-800 transition-colors"
                >
                  Lamar Sekarang
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'profile' && (
        <div className="space-y-6">
          {/* Data Pribadi */}
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
             <div className="flex items-center gap-2 mb-6 border-b pb-2">
                <UserCircle className="text-blue-600" />
                <h2 className="text-xl font-bold">Data Pribadi</h2>
             </div>

             <div className="grid md:grid-cols-3 gap-6">
                <div className="space-y-4">
                   <div>
                      <label className="flex items-center gap-1 text-sm font-medium mb-1"><UserIcon size={14}/> Nama Lengkap</label>
                      <input type="text" className="w-full p-2 border rounded" value={profileForm.name} onChange={e => setProfileForm({...profileForm, name: e.target.value})} />
                   </div>
                   <div>
                      <label className="flex items-center gap-1 text-sm font-medium mb-1"><Hash size={14}/> NIS / NISN</label>
                      <input type="text" className="w-full p-2 border rounded" placeholder="Masukkan NIS" value={profileForm.nis || ''} onChange={e => setProfileForm({...profileForm, nis: e.target.value})} />
                   </div>
                   <div>
                      <label className="flex items-center gap-1 text-sm font-medium mb-1"><Mail size={14}/> Email</label>
                      <input type="email" className="w-full p-2 border rounded bg-slate-100" value={profileForm.email} disabled />
                   </div>
                </div>

                <div className="space-y-4">
                   <div className="grid grid-cols-2 gap-2">
                      <div>
                         <label className="flex items-center gap-1 text-sm font-medium mb-1"><MapPin size={14}/> Tempat Lahir</label>
                         <input type="text" className="w-full p-2 border rounded" value={profileForm.birthPlace || ''} onChange={e => setProfileForm({...profileForm, birthPlace: e.target.value})} />
                      </div>
                      <div>
                         <label className="flex items-center gap-1 text-sm font-medium mb-1"><Calendar size={14}/> Tgl Lahir</label>
                         <input type="date" className="w-full p-2 border rounded text-sm" value={profileForm.birthDate || ''} onChange={e => setProfileForm({...profileForm, birthDate: e.target.value})} />
                      </div>
                   </div>
                   <div>
                      <label className="flex items-center gap-1 text-sm font-medium mb-1">Jenis Kelamin</label>
                      <select className="w-full p-2 border rounded bg-white" value={profileForm.gender || ''} onChange={e => setProfileForm({...profileForm, gender: e.target.value as any})}>
                         <option value="">Pilih...</option>
                         <option value="Laki-laki">Laki-laki</option>
                         <option value="Perempuan">Perempuan</option>
                      </select>
