                   <label className="block text-sm font-medium mb-1">Nama Perusahaan / Tempat Kerja</label>
                   <input type="text" className="w-full p-2 border rounded" value={profileForm.tracerCompany || ''} onChange={e => setProfileForm({...profileForm, tracerCompany: e.target.value})} />
                </div>
              )}
              {profileForm.tracerStatus === TracerStatus.STUDYING && (
                <div>
                   <label className="block text-sm font-medium mb-1">Nama Universitas / Kampus</label>
                   <input type="text" className="w-full p-2 border rounded" value={profileForm.tracerUniversity || ''} onChange={e => setProfileForm({...profileForm, tracerUniversity: e.target.value})} />
                </div>
              )}
               {profileForm.tracerStatus === TracerStatus.ENTREPRENEUR && (
                <div>
                   <label className="block text-sm font-medium mb-1">Nama Usaha / Bidang</label>
                   <input type="text" className="w-full p-2 border rounded" value={profileForm.tracerBusiness || ''} onChange={e => setProfileForm({...profileForm, tracerBusiness: e.target.value})} />
                </div>
              )}

              <button onClick={handleUpdateProfile} className="w-full mt-4 bg-green-600 text-white py-3 rounded-lg font-medium hover:bg-green-700 flex justify-center items-center gap-2">
                 <CheckCircle size={18} /> Submit Data Tracer
              </button>
           </div>
        </div>
      )}
    </div>
  );
};

