mohon diubah pada user alumini / siswa untuk halaman profil & CV dengan script berikut // Ganti ID ini dengan ID Google Sheet Anda
const SPREADSHEET_ID = '15HexCJ37DxKQVsNPyvzZuagTI-5QKQ8dvA_qNGywrso'; 
const SHEET_NAME = 'input data siswa';

/**
 * Fungsi doGet dipanggil ketika Web App diakses.
 * Fungsi ini memuat dan menyajikan konten dari index.html.
 */
function doGet() {
  return HtmlService.createTemplateFromFile('index')
      .evaluate()
      .setTitle('Formulir Data Siswa / Alumni BKK');
}

/**
 * Fungsi doPost ini dipanggil oleh google.script.run dari klien.
 * Parameter 'clientData' menerima objek data formulir yang Anda kirim.
 * @param {Object} clientData - Objek data formulir dari klien.
 */
function doPost(clientData) {
  try {
    // Memastikan koneksi ke sheet
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const sheet = ss.getSheetByName(SHEET_NAME);

    if (!sheet) {
      throw new Error("Sheet dengan nama '" + SHEET_NAME + "' tidak ditemukan.");
    }

    // PENTING: Kunci (key) harus cocok persis dengan yang ada di index.html (clientData['key']).
    // Pastikan urutan array newRow ini sesuai dengan urutan kolom di Sheet Anda.
    // Header kolom: Nis, Nama, Tempat Lahir, Tgl Lahir, Alamat Lengkap, Jenis Kelamin, No. WhatsApp, File CV (Format PDF), Ringkasan Profesional, Skill Utama, TAHUN LULUS, JURUSAN, EMAIL
    const newRow = [
      clientData['Nis'] || '',
      clientData['Nama'] || '',
      clientData['Tempat Lahir'] || '',
      clientData['Tgl Lahir'] || '',
      clientData['Alamat Lengkap'] || '',
      clientData['Jenis Kelamin'] || '',
      clientData['No. WhatsApp'] || '',
      clientData['File CV (Format PDF)'] || '',
      clientData['Ringkasan Profesional'] || '',
      clientData['Skill Utama'] || '',
      clientData['TAHUN LULUS'] || '',
      clientData['JURUSAN'] || '',
      clientData['EMAIL'] || '',
      new Date() // Timestamp pengiriman
    ];

    sheet.appendRow(newRow);

    // Kembalikan respons sukses ke google.script.run (onServerSuccess di klien)
    return { status: 'success', message: 'Data berhasil disimpan!' };

  } catch (error) {
    Logger.log("Ralat saat memproses data: " + error.toString());
    // Lempar error agar ditangkap oleh .withFailureHandler (onServerError di klien)
    throw new Error('Ralat penyimpanan: ' + error.message);
  }
}

