  const [activeTab, setActiveTab] = useState<'profile' | 'jobs' | 'tracer'>('jobs');
  const [jobs, setJobs] = useState<JobVacancy[]>([]);
  const [profileForm, setProfileForm] = useState<Partial<User>>(currentUser);
  const [isAiWorking, setIsAiWorking] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    setJobs(StorageService.getJobs().filter(j => j.isApproved));
  }, []);

  const handleUpdateProfile = async () => {
    setIsSubmitting(true);

    // Simulasi penyiapan data sesuai format Google Apps Script clientData
    const clientData = {
      'Nis': profileForm.nis || '',
      'Nama': profileForm.name || '',
      'Tempat Lahir': profileForm.birthPlace || '',
      'Tgl Lahir': profileForm.birthDate || '',
      'Alamat Lengkap': profileForm.address || '',
      'Jenis Kelamin': profileForm.gender || '',
      'No. WhatsApp': profileForm.whatsapp || '',
      'File CV (Format PDF)': profileForm.cvFileName || '',
      'Ringkasan Profesional': profileForm.cvSummary || '',
      'Skill Utama': profileForm.skills?.join(', ') || '',
      'TAHUN LULUS': profileForm.graduationYear || '',
      'JURUSAN': profileForm.major || '',
      'EMAIL': profileForm.email || ''
    };

    console.log('Data yang akan dikirim ke Google Sheet:', clientData);

    // Tetap simpan secara lokal untuk persistensi sesi
    const updated = { ...currentUser, ...profileForm };
    StorageService.saveUser(updated);
    onUpdateUser(updated as User);

    // Simulasi delay pengiriman
    setTimeout(() => {
      setIsSubmitting(false);
      alert('Profil Anda telah berhasil diperbarui dan disinkronkan dengan Database BKK!');
    }, 1000);
  };

  const handleAiSummary = async () => {
    if (!profileForm.cvSummary || !profileForm.major) return alert('Isi jurusan dan ringkasan saat ini dulu.');
    setIsAiWorking(true);
    const betterSummary = await GeminiService.improveCVSummary(profileForm.cvSummary, profileForm.major);
    setProfileForm({ ...profileForm, cvSummary: betterSummary });
    setIsAiWorking(false);
  };

  const handleApply = (jobTitle: string) => {
    const isProfileComplete = 
      currentUser.major && 
      currentUser.graduationYear && 
      currentUser.cvSummary && 
      currentUser.cvSummary.trim() !== "" &&
      currentUser.skills && 
      currentUser.skills.length > 0;

    if (!isProfileComplete) {
      alert("Mohon lengkapi profil dan CV Anda sebelum melamar pekerjaan.");
      setActiveTab('profile');
      return;
    }

    alert(`Lamaran Anda untuk posisi "${jobTitle}" telah berhasil dikirim!`);
  };

  const handleCvUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) {
        alert("Ukuran file terlalu besar. Maksimal 2MB.");
        return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        setProfileForm({
          ...profileForm,
          cvUrl: reader.result as string,
          cvFileName: file.name
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemoveCv = () => {
    if (confirm("Hapus file CV yang sudah diupload?")) {
      setProfileForm({
        ...profileForm,
        cvUrl: undefined,
        cvFileName: undefined
      });
    }
  };

  const filteredJobs = jobs.filter(j => 
    j.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
    j.companyName.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="max-w-6xl mx-auto p-4 md:p-6 space-y-6">
      <div className="flex flex-col md:flex-row gap-4 items-center justify-between mb-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Selamat Datang, {currentUser.name}</h1>
          <p className="text-slate-500">
            Status Akun: <span className={currentUser.isValidated ? "text-green-600 font-bold" : "text-yellow-600 font-bold"}>
              {currentUser.isValidated ? "Terverifikasi oleh BKK" : "Menunggu Verifikasi Sekolah"}
            </span>
          </p>
        </div>
        <div className="flex bg-white rounded-lg shadow-sm border border-slate-200 p-1">
          {[
            { id: 'jobs', icon: Briefcase, label: 'Lowongan Kerja' },
            { id: 'tracer', icon: GraduationCap, label: 'Tracer Study' },
            { id: 'profile', icon: UserIcon, label: 'Profil & CV' },
          ].map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id as any)}
              className={`flex items-center gap-2 px-4 py-2 rounded-md transition-all ${
                activeTab === item.id 
                  ? 'bg-blue-600 text-white shadow-md' 
                  : 'text-slate-600 hover:bg-slate-50'
              }`}
            >
              <item.icon size={18} /> <span className="hidden md:inline">{item.label}</span>
            </button>
          ))}
        </div>
      </div>

      {activeTab === 'jobs' && (
        <div className="space-y-4">
          <div className="relative">
            <input 
              type="text" 
              placeholder="Cari lowongan berdasarkan posisi atau nama perusahaan..." 
              className="w-full p-4 pl-12 border border-slate-300 rounded-xl shadow-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
            <Briefcase className="absolute left-4 top-4 text-slate-400" size={20} />
          </div>
          <div className="grid md:grid-cols-2 gap-4">
            {filteredJobs.length === 0 && (
              <div className="text-center py-20 col-span-2 bg-white rounded-xl border border-dashed border-slate-300">
                <p className="text-slate-500">Belum ada lowongan kerja yang tersedia saat ini.</p>
              </div>
            )}
            {filteredJobs.map(job => (
              <div key={job.id} className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-shadow">
                <div className="flex justify-between items-start mb-2">
                   <div>
                      <h3 className="font-bold text-lg text-slate-900">{job.title}</h3>
                      <p className="text-blue-600 font-medium">{job.companyName}</p>
                   </div>
                   <span className="text-xs font-bold bg-slate-100 text-slate-600 px-3 py-1 rounded-full">{job.type}</span>
                </div>
                <div className="flex items-center text-slate-500 text-sm mb-4 gap-1">
                   <MapPin size={14} /> {job.location}
                </div>
                <p className="text-slate-600 text-sm mb-4 line-clamp-2">{job.description}</p>
                <div className="flex flex-wrap gap-2 mb-4">
                  {job.requirements.slice(0, 3).map((req, i) => (
                    <span key={i} className="text-xs bg-blue-50 text-blue-700 px-2 py-1 rounded-md border border-blue-100">{req}</span>
                  ))}
                </div>
                <button 
                  onClick={() => handleApply(job.title)}
                  className="w-full bg-slate-900 text-white py-3 rounded-lg font-bold hover:bg-slate-800 transition-colors shadow-lg shadow-slate-200"
                >
                  Lamar Sekarang
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'profile' && (
        <div className="space-y-6">
          {/* Identitas Diri (Sesuai kolom Sheet) */}
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
             <div className="flex items-center gap-2 mb-6 border-b pb-4">
                <UserCircle className="text-blue-600" size={24} />
                <h2 className="text-xl font-bold">Data Biodata Siswa/Alumni</h2>
             </div>

             <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                <div className="space-y-4">
                   <div>
                      <label className="flex items-center gap-1 text-sm font-semibold text-slate-700 mb-1"><Hash size={14}/> Nis / Nisn</label>
                      <input type="text" className="w-full p-2.5 border rounded-lg bg-slate-50" placeholder="Nomor Induk Siswa" value={profileForm.nis || ''} onChange={e => setProfileForm({...profileForm, nis: e.target.value})} />
                   </div>
                   <div>
                      <label className="flex items-center gap-1 text-sm font-semibold text-slate-700 mb-1"><UserIcon size={14}/> Nama Lengkap</label>
                      <input type="text" className="w-full p-2.5 border rounded-lg bg-slate-50" placeholder="Nama Sesuai Ijazah" value={profileForm.name} onChange={e => setProfileForm({...profileForm, name: e.target.value})} />
                   </div>
                   <div>
                      <label className="flex items-center gap-1 text-sm font-semibold text-slate-700 mb-1"><Mail size={14}/> Email Aktif</label>
                      <input type="email" className="w-full p-2.5 border rounded-lg bg-slate-100 text-slate-500" value={profileForm.email} disabled />
                   </div>
                </div>

                <div className="space-y-4">
                   <div className="grid grid-cols-2 gap-2">
                      <div>
                         <label className="flex items-center gap-1 text-sm font-semibold text-slate-700 mb-1"><MapPin size={14}/> Tempat Lahir</label>
                         <input type="text" className="w-full p-2.5 border rounded-lg bg-slate-50" value={profileForm.birthPlace || ''} onChange={e => setProfileForm({...profileForm, birthPlace: e.target.value})} />
                      </div>
                      <div>
                         <label className="flex items-center gap-1 text-sm font-semibold text-slate-700 mb-1"><Calendar size={14}/> Tgl Lahir</label>
                         <input type="date" className="w-full p-2.5 border rounded-lg bg-slate-50 text-sm" value={profileForm.birthDate || ''} onChange={e => setProfileForm({...profileForm, birthDate: e.target.value})} />
                      </div>
                   </div>
                   <div>
                      <label className="flex items-center gap-1 text-sm font-semibold text-slate-700 mb-1">Jenis Kelamin</label>
                      <select className="w-full p-2.5 border rounded-lg bg-white" value={profileForm.gender || ''} onChange={e => setProfileForm({...profileForm, gender: e.target.value as any})}>
                         <option value="">Pilih Jenis Kelamin...</option>
                         <option value="Laki-laki">Laki-laki</option>
                         <option value="Perempuan">Perempuan</option>
                      </select>
                   </div>
                   <div>
                      <label className="flex items-center gap-1 text-sm font-semibold text-slate-700 mb-1"><Phone size={14}/> No. WhatsApp</label>
                      <input type="text" className="w-full p-2.5 border rounded-lg bg-slate-50" placeholder="Contoh: 08123456789" value={profileForm.whatsapp || ''} onChange={e => setProfileForm({...profileForm, whatsapp: e.target.value})} />
                   </div>
                </div>

                <div className="space-y-4">
                   <div>
                      <label className="flex items-center gap-1 text-sm font-semibold text-slate-700 mb-1"><Map size={14}/> Alamat Lengkap</label>
                      <textarea className="w-full p-2.5 border rounded-lg bg-slate-50 h-[108px] text-sm resize-none" placeholder="Isi alamat lengkap tempat tinggal saat ini" value={profileForm.address || ''} onChange={e => setProfileForm({...profileForm, address: e.target.value})} />
                   </div>
                   <div>
                      <label className="flex items-center gap-1 text-sm font-semibold text-slate-700 mb-1"><Linkedin size={14}/> Link LinkedIn (Opsional)</label>
                      <input type="text" className="w-full p-2.5 border rounded-lg bg-slate-50" placeholder="https://linkedin.com/..." value={profileForm.linkedin || ''} onChange={e => setProfileForm({...profileForm, linkedin: e.target.value})} />
                   </div>
                </div>
             </div>
          </div>

          {/* Data Pendidikan & Karir (Sesuai kolom Sheet) */}
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
             <div className="flex items-center gap-2 mb-6 border-b pb-4">
                <GraduationCap className="text-green-600" size={24} />
                <h2 className="text-xl font-bold">Data Pendidikan & CV Profesional</h2>
             </div>

             <div className="grid md:grid-cols-2 gap-8">
                <div className="space-y-6">
                   <div className="grid grid-cols-2 gap-4">
                      <div>
                          <label className="block text-sm font-semibold text-slate-700 mb-1">Tahun Lulus</label>
                          <input type="number" className="w-full p-2.5 border rounded-lg bg-slate-50" placeholder="Tahun" value={profileForm.graduationYear || ''} onChange={e => setProfileForm({...profileForm, graduationYear: parseInt(e.target.value)})} />
                      </div>
                      <div>
                          <label className="block text-sm font-semibold text-slate-700 mb-1">Jurusan</label>
                          <input type="text" className="w-full p-2.5 border rounded-lg bg-slate-50" placeholder="Nama Jurusan" value={profileForm.major || ''} onChange={e => setProfileForm({...profileForm, major: e.target.value})} />
                      </div>
                   </div>

                   <div>
                      <label className="block text-sm font-semibold text-slate-700 mb-2">File CV (Format PDF)</label>
                      {!profileForm.cvUrl ? (
                        <div className="border-2 border-dashed border-slate-300 rounded-xl p-8 text-center hover:bg-slate-50 transition-all relative group">
                          <input 
                            type="file" 
                            accept=".pdf" 
                            onChange={handleCvUpload} 
                            className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                          />
                          <div className="group-hover:scale-110 transition-transform">
                             <Upload className="mx-auto text-slate-400 mb-3" size={32} />
                          </div>
                          <p className="text-sm text-slate-600 font-bold">Klik untuk Unggah CV PDF</p>
                          <p className="text-xs text-slate-400 mt-2 italic">Pastikan file dalam format PDF (Maks. 2MB)</p>
                        </div>
                      ) : (
                        <div className="flex items-center justify-between p-4 bg-blue-50 border border-blue-100 rounded-xl">
                          <div className="flex items-center gap-3 overflow-hidden">
                             <div className="bg-blue-100 p-2.5 rounded-lg text-blue-600">
                                <FileText size={24} />
                             </div>
                             <div className="min-w-0">
                                <p className="text-sm font-bold text-slate-800 truncate">{profileForm.cvFileName}</p>
                                <a href={profileForm.cvUrl} download={profileForm.cvFileName} className="text-xs text-blue-600 font-semibold hover:underline">Lihat File Upload</a>
                             </div>
                          </div>
                          <button onClick={handleRemoveCv} className="p-2 text-red-500 hover:bg-red-100 rounded-full transition-colors">
                             <Trash2 size={20} />
                          </button>
                        </div>
                      )}
                   </div>
                </div>

                <div className="space-y-4">
                   <div>
                      <div className="flex justify-between items-center mb-1">
                        <label className="block text-sm font-semibold text-slate-700">Ringkasan Profesional</label>
                        <button onClick={handleAiSummary} disabled={isAiWorking} className="text-xs flex items-center gap-1.5 text-purple-600 font-bold bg-purple-50 hover:bg-purple-100 px-3 py-1.5 rounded-lg transition-colors border border-purple-100">
                           <Sparkles size={14} /> {isAiWorking ? 'Sedang Memproses...' : 'Tingkatkan dengan AI'}
                        </button>
                      </div>
                      <textarea 
                        className="w-full p-2.5 border rounded-lg bg-slate-50 h-32 text-sm resize-none" 
                        placeholder="Ceritakan singkat tentang pengalaman kerja, prestasi, atau tujuan karir Anda..."
                        value={profileForm.cvSummary || ''} 
                        onChange={e => setProfileForm({...profileForm, cvSummary: e.target.value})} 
                      />
                   </div>
                   <div>
                      <label className="block text-sm font-semibold text-slate-700 mb-1">Skill Utama (Pisahkan dengan koma)</label>
                      <input 
                        type="text" 
                        className="w-full p-2.5 border rounded-lg bg-slate-50" 
                        placeholder="Contoh: Welding, Pemesinan CNC, AutoCAD, Ms. Office"
                        value={profileForm.skills?.join(', ') || ''} 
                        onChange={e => setProfileForm({...profileForm, skills: e.target.value.split(',').map(s => s.trim())})} 
                      />
                   </div>
                </div>
             </div>

             <div className="mt-10 flex justify-end">
               <button 
                onClick={handleUpdateProfile} 
                disabled={isSubmitting}
                className={`flex items-center gap-2 bg-blue-600 text-white px-10 py-4 rounded-xl font-bold transition-all shadow-xl shadow-blue-100 hover:bg-blue-700 active:scale-95 ${isSubmitting ? 'opacity-70 cursor-not-allowed' : ''}`}
               >
                 {isSubmitting ? (
                   <>
                     <Loader2 className="animate-spin" size={20} />
                     Sedang Menyimpan...
                   </>
                 ) : (
                   <>
                     <Send size={20} />
                     Simpan & Kirim Data ke BKK
                   </>
                 )}
               </button>
             </div>
          </div>
        </div>
      )}

      {activeTab === 'tracer' && (
        <div className="max-w-2xl mx-auto bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
           <div className="flex items-center gap-2 mb-4">
              <GraduationCap className="text-blue-600" size={28} />
              <h2 className="text-2xl font-bold">Formulir Tracer Study</h2>
           </div>
           <p className="text-slate-600 mb-8 text-sm">Data keterserapan alumni sangat penting bagi sekolah untuk peningkatan kualitas mutu lulusan SMK Tanjung Priok 1.</p>

           <div className="space-y-6">
              <div>
                <label className="block text-sm font-bold text-slate-700 mb-3">Status Keterserapan Saat Ini:</label>
                <div className="grid grid-cols-2 gap-4">
                  {Object.values(TracerStatus).map(status => (
                    <button
                      key={status}
                      onClick={() => setProfileForm({...profileForm, tracerStatus: status})}
                      className={`p-4 rounded-xl border-2 font-bold transition-all text-left flex items-center justify-between ${
                        profileForm.tracerStatus === status 
                          ? 'border-blue-600 bg-blue-50 text-blue-700' 
                          : 'border-slate-100 hover:border-slate-200 text-slate-600'
                      }`}
                    >
                      {status}
                      {profileForm.tracerStatus === status && <CheckCircle size={18} />}
                    </button>
                  ))}
                </div>
              </div>

              {profileForm.tracerStatus === TracerStatus.WORKING && (
                <div className="animate-in fade-in slide-in-from-top-2 duration-300">
                   <label className="block text-sm font-semibold text-slate-700 mb-1">Nama Instansi / Perusahaan Tempat Kerja</label>
                   <input type="text" className="w-full p-3 border rounded-lg bg-slate-50 focus:ring-2 focus:ring-blue-500 outline-none" placeholder="Masukkan nama PT/Perusahaan" value={profileForm.tracerCompany || ''} onChange={e => setProfileForm({...profileForm, tracerCompany: e.target.value})} />
                </div>
              )}
              {profileForm.tracerStatus === TracerStatus.STUDYING && (
                <div className="animate-in fade-in slide-in-from-top-2 duration-300">
                   <label className="block text-sm font-semibold text-slate-700 mb-1">Nama Universitas / Kampus</label>
                   <input type="text" className="w-full p-3 border rounded-lg bg-slate-50 focus:ring-2 focus:ring-blue-500 outline-none" placeholder="Masukkan nama kampus" value={profileForm.tracerUniversity || ''} onChange={e => setProfileForm({...profileForm, tracerUniversity: e.target.value})} />
                </div>
              )}
               {profileForm.tracerStatus === TracerStatus.ENTREPRENEUR && (
                <div className="animate-in fade-in slide-in-from-top-2 duration-300">
                   <label className="block text-sm font-semibold text-slate-700 mb-1">Bidang Usaha / Nama Usaha</label>
                   <input type="text" className="w-full p-3 border rounded-lg bg-slate-50 focus:ring-2 focus:ring-blue-500 outline-none" placeholder="Contoh: Bengkel Motor Berdikari" value={profileForm.tracerBusiness || ''} onChange={e => setProfileForm({...profileForm, tracerBusiness: e.target.value})} />
                </div>
              )}

              <button 
                onClick={handleUpdateProfile} 
                className="w-full mt-6 bg-green-600 text-white py-4 rounded-xl font-bold hover:bg-green-700 transition-all flex justify-center items-center gap-2 shadow-lg shadow-green-100"
              >
                 <CheckCircle size={20} /> Submit Data Tracer Study
              </button>
           </div>
        </div>
      )}
    </div>
  );
};

// Simple loader component
const Loader2 = ({ className, size }: { className?: string, size?: number }) => (
  <svg className={`${className} animate-spin`} width={size || 24} height={size || 24} viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
  </svg>
);

import React, { useState, useEffect } from 'react';
import { User, JobVacancy, TracerStatus } from '../types';
import { StorageService } from '../services/storageService';
import { GeminiService } from '../services/geminiService';
import { 
  Briefcase, User as UserIcon, GraduationCap, MapPin, Sparkles, 
  CheckCircle, Upload, FileText, Trash2, Phone, Calendar, 
  UserCircle, Map, Linkedin, Mail, Hash, Send, Loader2
} from 'lucide-react';

interface Props {
  currentUser: User;
  onUpdateUser: (user: User) => void;
}

export const AlumniDashboard: React.FC<Props> = ({ currentUser, onUpdateUser }) => {
  const [activeTab, setActiveTab] = useState<'profile' | 'jobs' | 'tracer'>('jobs');
  const [jobs, setJobs] = useState<JobVacancy[]>([]);
  const [profileForm, setProfileForm] = useState<Partial<User>>(currentUser);
  const [isAiWorking, setIsAiWorking] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // URL Google Apps Script Web App (Dipublikasikan sebagai "Anyone")
  const GAS_WEB_APP_URL = 'https://script.google.com/macros/s/AKfycbzt5nopU9DwdC_79dN3eFaK45kpuIXURTrLiejxWJmN/exec';

  useEffect(() => {
    setJobs(StorageService.getJobs().filter(j => j.isApproved));
  }, []);

  const syncWithGoogleSheet = async (data: any) => {
    try {
      // Mengirim data menggunakan format POST ke GAS
      // Menggunakan mode: 'no-cors' karena GAS sering redirect, 
      // namun ini berarti kita tidak bisa membaca respon JSON secara langsung.
      // Untuk implementasi production yang lebih baik, GAS harus menangani OPTIONS request.
      await fetch(GAS_WEB_APP_URL, {
        method: 'POST',
        mode: 'no-cors', 
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(data),
      });
      return true;
    } catch (error) {
      console.error('Gagal sinkronisasi ke Google Sheet:', error);
      return false;
    }
  };

  const handleUpdateProfile = async () => {
    if (!profileForm.name || !profileForm.nis) {
      alert("Nama dan NIS wajib diisi.");
      return;
    }

    setIsSubmitting(true);

    // Siapkan clientData sesuai spesifikasi kolom Google Sheet
    const clientData = {
      'Nis': profileForm.nis || '',
      'Nama': profileForm.name || '',
      'Tempat Lahir': profileForm.birthPlace || '',
      'Tgl Lahir': profileForm.birthDate || '',
      'Alamat Lengkap': profileForm.address || '',
      'Jenis Kelamin': profileForm.gender || '',
      'No. WhatsApp': profileForm.whatsapp || '',
      'File CV (Format PDF)': profileForm.cvFileName || 'Belum upload',
      'Ringkasan Profesional': profileForm.cvSummary || '',
      'Skill Utama': profileForm.skills?.join(', ') || '',
      'TAHUN LULUS': profileForm.graduationYear?.toString() || '',
      'JURUSAN': profileForm.major || '',
      'EMAIL': profileForm.email || ''
    };

    // 1. Simpan Lokal terlebih dahulu
    const updated = { ...currentUser, ...profileForm };
    StorageService.saveUser(updated);
    onUpdateUser(updated as User);

    // 2. Sinkronisasi ke Google Sheet
    const isSynced = await syncWithGoogleSheet(clientData);

    setIsSubmitting(false);
    if (isSynced) {
      alert('Data Berhasil Disimpan & Disinkronkan ke Database BKK Sekolah!');
    } else {
