  }, []);

  // FUNGSI SAMBUNGAN UTAMA KE GOOGLE APPS SCRIPT
  const submitToGoogleSheets = async (formData: any, scriptUrl: string) => {
    try {
      // First attempt using JSON with no-cors
      await fetch(scriptUrl, {
        method: 'POST',
        mode: 'no-cors',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData)
      });

      // Second attempt using URLSearchParams (Backup logic for GAS legacy)
      const formParams = new URLSearchParams();
      Object.keys(formData).forEach(key => {
        formParams.append(key, formData[key]);
      });

      // We don't wait for the second attempt if we want speed, but GAS handles no-cors redirects silently.
      // In a no-cors environment, we assume success if no crash.
      return true;
    } catch (error) {
      console.error("Ralat sambungan GAS:", error);
      return false;
    }
  };

  const handleUpdateProfile = async () => {
    // Validasi Dasar
    if (!profileForm.name || !profileForm.nis || !profileForm.graduationYear || !profileForm.major) {
      alert("Mohon lengkapi field wajib (Nama, NIS, Tahun Lulus, Jurusan).");
      return;
    }

    setIsSubmitting(true);

    // Pemetaan Data (Mapping) sesuai label kolom Google Sheets
    const clientData = {
      'Nis': profileForm.nis || '',
      'Nama': profileForm.name || '',
      'Tempat Lahir': profileForm.birthPlace || '',
      'Tgl Lahir': profileForm.birthDate || '',
      'Alamat Lengkap': profileForm.address || '',
      'Jenis Kelamin': profileForm.gender || '',
      'No. WhatsApp': profileForm.whatsapp || '',
      'File CV (Format PDF)': profileForm.cvFileName || 'Belum upload',
      'Ringkasan Profesional': profileForm.cvSummary || '',
      'Skill Utama (Pisahkan dengan koma)': profileForm.skills?.join(', ') || '',
      'TAHUN LULUS': profileForm.graduationYear?.toString() || '',
      'JURUSAN': profileForm.major || '',
      'EMAIL': profileForm.email || '',
      'NO_Tlp': profileForm.noTlp || '',
      'NO_urut': profileForm.noUrut || ''
    };

    // Sinkronisasi lokal
    const updated = { ...currentUser, ...profileForm };
    StorageService.saveUser(updated);
    onUpdateUser(updated as User);

    // Kirim ke Google Sheets
    const success = await submitToGoogleSheets(clientData, SCRIPT_URL);

    setIsSubmitting(false);
    if (success) {
      alert('Data Profil & CV Berhasil Dikirim ke Database BKK Sekolah!');
    } else {
