import React, { useState, useEffect } from 'react';
import { User, JobVacancy, TracerStatus } from '../types';
import { StorageService } from '../services/storageService';
import { GeminiService } from '../services/geminiService';
import { 
  Briefcase, User as UserIcon, GraduationCap, MapPin, Sparkles, 
  CheckCircle, Upload, FileText, Trash2, Phone, Calendar, 
  UserCircle, Map, Mail, Hash, Send, Loader2,
  Info, Smartphone, ListOrdered, ChevronRight, X, Star
} from 'lucide-react';

interface Props {
  currentUser: User;
  onUpdateUser: (user: User) => void;
}

export const AlumniDashboard: React.FC<Props> = ({ currentUser, onUpdateUser }) => {
  const [activeTab, setActiveTab] = useState<'profile' | 'jobs' | 'tracer'>('profile');
  const [jobs, setJobs] = useState<JobVacancy[]>([]);
  const [profileForm, setProfileForm] = useState<Partial<User>>(currentUser);
  const [isAiWorking, setIsAiWorking] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // SCRIPT CONFIGURATION
  const SCRIPT_URL = 'https://script.google.com/macros/s/AKfycbzt5nopU9DwdC_79dN3eFaK45kpuIXURTrLiejxWJmN/exec';

  useEffect(() => {
    setJobs(StorageService.getJobs().filter(j => j.isApproved));
  }, []);

  // FUNGSI SAMBUNGAN UTAMA KE GOOGLE APPS SCRIPT (Sesuai Permintaan)
  async function submitToGoogleSheets(formData: any, scriptUrl: string) {
    try {
      // First attempt using JSON with no-cors
      await fetch(scriptUrl, {
        method: 'POST',
        mode: 'no-cors',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData)
      });

      // Second attempt using URLSearchParams
      const formParams = new URLSearchParams();
      Object.keys(formData).forEach(key => {
        formParams.append(key, formData[key]);
      });

      await fetch(scriptUrl, {
        method: 'POST',
        mode: 'no-cors',
        headers: {
